/**
 * @param {number[]} digitSum
 * @return {number}
 */
function solve(digitSum) {
    const MOD = 1000000007;
    const MAX_VAL = 5000;

    /**
     * Helper function to calculate the sum of digits of a number.
     * @param {number} n
     * @returns {number}
     */
    const getDigitSum = (n) => {
        let sum = 0;
        n = Math.abs(n);
        while (n > 0) {
            sum += n % 10;
            n = Math.floor(n / 10);
        }
        return sum;
    };

    /**
     * Precompute all numbers up to MAX_VAL (5000) and their digit sums.
     * Map: digitSum -> array of numbers having that digit sum.
     */
    const numbersByDigitSum = new Map();

    for (let i = 0; i <= MAX_VAL; i++) {
        const ds = getDigitSum(i);
        if (!numbersByDigitSum.has(ds)) {
            numbersByDigitSum.set(ds, []);
        }
        numbersByDigitSum.get(ds).push(i);
    }

    // Sort the lists of numbers for easier non-decreasing check
    for (const [ds, nums] of numbersByDigitSum.entries()) {
        nums.sort((a, b) => a - b);
    }

    // dp[i][j] will store the number of valid prefixes of length i, where the i-th element is the j-th smallest number
    // that satisfies the digit sum digitSum[i-1].
    const n = digitSum.length;

    // We need to map the available numbers to an index for DP state.
    // Let's map the required digit sums to the actual lists of numbers.
    const requiredNumberLists = [];
    for (let i = 0; i < n; i++) {
        const ds = digitSum[i];
        if (!numbersByDigitSum.has(ds)) {
            return 0; // Impossible for this element
        }
        // Store the sorted list of valid numbers for digitSum[i]
        requiredNumberLists.push(numbersByDigitSum.get(ds));
    }

    // dp[i][j]: Number of ways to form a valid sequence of length i+1, 
    // where the (i+1)-th element is requiredNumberLists[i][j] (the j-th smallest number with digitSum[i]).

    // Initialize DP table. dp[i] is the array for the i-th position (0-indexed).
    const dp = new Array(n);

    // Base case: i = 0 (The first element)
    const L0 = requiredNumberLists[0];
    dp[0] = new Array(L0.length).fill(1); // Any valid number for the first position is a valid start sequence of length 1.

    // Iteration for i = 1 to n-1
    for (let i = 1; i < n; i++) {
        const Li = requiredNumberLists[i];
        const Li_1 = requiredNumberLists[i-1];
        const dp_i = new Array(Li.length).fill(0);

        for (let j = 0; j < Li.length; j++) {
            const current_num = Li[j];
            let count = 0;

            // Sum up counts from dp[i-1][k] where Li_1[k] <= current_num
            for (let k = 0; k < Li_1.length; k++) {
                const prev_num = Li_1[k];
                if (prev_num <= current_num) {
                    count = (count + dp[i - 1][k]) % MOD;
                } else {
                    // Since Li_1 is sorted, we can break early
                    break;
                }
            }
            dp_i[j] = count;
        }
        dp[i] = dp_i;
    }

    // Final result: Sum of all entries in the last DP array dp[n-1]
    let totalCount = 0;
    if (n > 0) {
        for (let j = 0; j < dp[n - 1].length; j++) {
            totalCount = (totalCount + dp[n - 1][j]) % MOD;
        }
    }

    return totalCount;
}

